import React, { useEffect, useState, useCallback } from 'react';
import {
  Card,
  Button,
  dispatchAppToast,
} from '@linm-soft-org/linm-web-common-components';
import {
  Title,
  Text,
  Tag,
  Modal,
  Popconfirm,
  Space,
  Spin,
} from '@/components/common';
import { useAppDispatch } from '../../../store/hooks';
import { fpcService } from '../../../services/fpc/service';
import type { ExpansionSimulationDto, CreateExpansionSimulationDto, UpdateExpansionSimulationDto } from '../../../services/fpc/types';
import styles from './NewBranchSimulatorPage.module.css';

/* ── Inline table styles ── */
const tableCss: React.CSSProperties = {
  width: '100%', borderCollapse: 'collapse', fontSize: 14,
};
const thCss: React.CSSProperties = {
  textAlign: 'left', padding: '8px 12px',
  borderBottom: '1px solid #e8e8e8', borderTop: '1px solid #e8e8e8',
  fontWeight: 600, background: '#fafafa',
};
const tdCss: React.CSSProperties = {
  padding: '8px 12px', borderBottom: '1px solid #e8e8e8',
};
const tdRight: React.CSSProperties = { ...tdCss, textAlign: 'right' };
const tdCenter: React.CSSProperties = { ...tdCss, textAlign: 'center' };

const formRow: React.CSSProperties = { display: 'flex', gap: 16, marginBottom: 16 };
const col50: React.CSSProperties = { flex: '0 0 calc(50% - 8px)' };
const labelCss: React.CSSProperties = {
  display: 'block', marginBottom: 4, fontWeight: 500, fontSize: 13,
};
const inputCss: React.CSSProperties = {
  width: '100%', padding: '6px 10px', fontSize: 14,
  border: '1px solid #d9d9d9', borderRadius: 4, boxSizing: 'border-box',
  outline: 'none',
};

/* ── Default form values ── */
const defaultForm = {
  name: '',
  capexFitOut: 0,
  capexEquipment: 0,
  preOpeningCost: 0,
  workingCapitalRequired: 0,
  initialInventoryValue: 0,
  projectedMonthlyRevenue: 0,
  targetGrossMarginPercent: 0,
  monthlyFixedCosts: 0,
  rampUpMonths: 3,
  rampUpRevenuePercent: 50,
};

export default function NewBranchSimulatorPage() {
  const dispatch = useAppDispatch();
  const [data, setData] = useState<ExpansionSimulationDto[]>([]);
  const [loading, setLoading] = useState(true);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<ExpansionSimulationDto | null>(null);
  const [formState, setFormState] = useState<Record<string, any>>(defaultForm);
  const [submitting, setSubmitting] = useState(false);

  /* ── Data fetching ── */

  const fetchData = useCallback(async () => {
    setLoading(true);
    try {
      const result = await fpcService.getExpansionSimList();
      setData(result);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  /* ── Helpers ── */

  const formatMoney = (v?: number) =>
    v !== undefined ? new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(v) : '-';

  const updateField = (field: string, value: any) =>
    setFormState((prev) => ({ ...prev, [field]: value }));

  const validateForm = (): boolean => {
    if (!formState.name?.trim()) {
      dispatchAppToast(dispatch, { message: 'Vui lòng nhập tên mô phỏng', type: 'warning' });
      return false;
    }
    const requiredNumbers = [
      'capexFitOut', 'capexEquipment', 'preOpeningCost',
      'workingCapitalRequired', 'initialInventoryValue',
      'projectedMonthlyRevenue', 'targetGrossMarginPercent', 'monthlyFixedCosts',
    ];
    for (const f of requiredNumbers) {
      if (formState[f] === undefined || formState[f] === null || formState[f] === '') {
        dispatchAppToast(dispatch, { message: 'Vui lòng điền đầy đủ thông tin', type: 'warning' });
        return false;
      }
    }
    return true;
  };

  /* ── Actions ── */

  const handleCreate = () => {
    setEditing(null);
    setFormState(defaultForm);
    setModalOpen(true);
  };

  const handleEdit = (record: ExpansionSimulationDto) => {
    setEditing(record);
    setFormState({
      name: record.name ?? '',
      capexFitOut: record.capexFitOut ?? 0,
      capexEquipment: record.capexEquipment ?? 0,
      preOpeningCost: record.preOpeningCost ?? 0,
      workingCapitalRequired: record.workingCapitalRequired ?? 0,
      initialInventoryValue: record.initialInventoryValue ?? 0,
      projectedMonthlyRevenue: record.projectedMonthlyRevenue ?? 0,
      targetGrossMarginPercent: record.targetGrossMarginPercent ?? 0,
      monthlyFixedCosts: record.monthlyFixedCosts ?? 0,
      rampUpMonths: record.rampUpMonths ?? 3,
      rampUpRevenuePercent: record.rampUpRevenuePercent ?? 50,
    });
    setModalOpen(true);
  };

  const handleSubmit = async () => {
    if (!validateForm()) return;
    setSubmitting(true);
    try {
      if (editing) {
        const dto: UpdateExpansionSimulationDto = {
          name: formState.name,
          capexFitOut: Number(formState.capexFitOut),
          capexEquipment: Number(formState.capexEquipment),
          preOpeningCost: Number(formState.preOpeningCost),
          workingCapitalRequired: Number(formState.workingCapitalRequired),
          initialInventoryValue: Number(formState.initialInventoryValue),
          projectedMonthlyRevenue: Number(formState.projectedMonthlyRevenue),
          targetGrossMarginPercent: Number(formState.targetGrossMarginPercent),
          monthlyFixedCosts: Number(formState.monthlyFixedCosts),
          rampUpMonths: Number(formState.rampUpMonths),
          rampUpRevenuePercent: Number(formState.rampUpRevenuePercent),
        };
        await fpcService.updateExpansionSim(editing.id, dto);
        dispatchAppToast(dispatch, { message: 'Đã cập nhật mô phỏng', type: 'success' });
      } else {
        const dto: CreateExpansionSimulationDto = {
          name: formState.name,
          capexFitOut: Number(formState.capexFitOut),
          capexEquipment: Number(formState.capexEquipment),
          preOpeningCost: Number(formState.preOpeningCost),
          workingCapitalRequired: Number(formState.workingCapitalRequired),
          initialInventoryValue: Number(formState.initialInventoryValue),
          projectedMonthlyRevenue: Number(formState.projectedMonthlyRevenue),
          targetGrossMarginPercent: Number(formState.targetGrossMarginPercent),
          monthlyFixedCosts: Number(formState.monthlyFixedCosts),
          rampUpMonths: Number(formState.rampUpMonths),
          rampUpRevenuePercent: Number(formState.rampUpRevenuePercent),
        };
        await fpcService.createExpansionSim(dto);
        dispatchAppToast(dispatch, { message: 'Đã tạo mô phỏng', type: 'success' });
      }
      setModalOpen(false);
      fetchData();
    } catch {
      dispatchAppToast(dispatch, { message: 'Có lỗi xảy ra', type: 'error' });
    } finally {
      setSubmitting(false);
    }
  };

  const handleRun = async (id: string) => {
    try {
      await fpcService.runExpansionSim(id);
      dispatchAppToast(dispatch, { message: 'Đã chạy mô phỏng', type: 'success' });
      fetchData();
    } catch {
      dispatchAppToast(dispatch, { message: 'Không thể chạy mô phỏng', type: 'error' });
    }
  };

  const handleDelete = async (id: string) => {
    try {
      await fpcService.deleteExpansionSim(id);
      dispatchAppToast(dispatch, { message: 'Đã xóa mô phỏng', type: 'success' });
      fetchData();
    } catch {
      dispatchAppToast(dispatch, { message: 'Không thể xóa mô phỏng', type: 'error' });
    }
  };

  /* ── Tag color mapping ── */
  const statusTagColor = (v: string): string | undefined =>
    v === 'Completed' ? '#3f8600' : v === 'Running' ? '#1677ff' : undefined;

  const statusLabel = (v: string): string => {
    switch (v) {
      case 'Draft': return 'Bản nháp';
      case 'Running': return 'Đang chạy';
      case 'Completed': return 'Hoàn thành';
      case 'Failed': return 'Thất bại';
      default: return v;
    }
  };

  /* ── Numeric input helper ── */
  const numInput = (
    field: string,
    placeholder: string,
  ) => (
    <input
      type="number"
      style={inputCss}
      placeholder={placeholder}
      value={formState[field] ?? ''}
      onChange={(e) => updateField(field, e.target.value === '' ? '' : Number(e.target.value))}
    />
  );

  /* ── Render ── */

  return (
    <div className={styles.page}>
      <Title level={3}>Mô phỏng Mở rộng Chi nhánh</Title>

      <Card style={{ marginBottom: 16 }}>
        <Button variant="primary" size="md" onClick={handleCreate}>
          <i className="fas fa-plus" style={{ marginRight: 6 }} />
          Mô phỏng mới
        </Button>
      </Card>

      {loading ? (
        <div style={{ textAlign: 'center', padding: 48 }}>
          <Spin size="large" />
        </div>
      ) : (
        <table style={tableCss}>
          <thead>
            <tr>
              <th style={thCss}>Tên</th>
              <th style={thCss}>Trạng thái</th>
              <th style={{ ...thCss, textAlign: 'right' }}>Tổng đầu tư</th>
              <th style={{ ...thCss, textAlign: 'right' }}>Hoà vốn (tháng)</th>
              <th style={{ ...thCss, textAlign: 'right' }}>Hoàn vốn (tháng)</th>
              <th style={{ ...thCss, textAlign: 'right' }}>Dòng tiền/tháng</th>
              <th style={{ ...thCss, textAlign: 'right' }}>LN 12 tháng</th>
              <th style={thCss}>Đề xuất</th>
              <th style={{ ...thCss, textAlign: 'center', width: 120 }} />
            </tr>
          </thead>
          <tbody>
            {data.length === 0 ? (
              <tr>
                <td colSpan={9} style={{ ...tdCss, textAlign: 'center', color: '#999' }}>
                  Chưa có mô phỏng nào
                </td>
              </tr>
            ) : (
              data.map((record) => (
                <tr key={record.id}>
                  <td style={tdCss}>{record.name}</td>
                  <td style={tdCss}>
                    <Tag color={statusTagColor(record.status)}>{statusLabel(record.status)}</Tag>
                  </td>
                  <td style={tdRight}>{formatMoney(record.totalInvestment)}</td>
                  <td style={tdRight}>{record.breakEvenMonth ?? '-'}</td>
                  <td style={tdRight}>{record.paybackMonths ?? '-'}</td>
                  <td style={tdRight}>
                    <Text
                      type={
                        record.monthlyNetCashflow !== undefined && record.monthlyNetCashflow >= 0
                          ? 'success'
                          : 'danger'
                      }
                    >
                      {formatMoney(record.monthlyNetCashflow)}
                    </Text>
                  </td>
                  <td style={tdRight}>
                    <Text
                      type={
                        record.twelveMonthProfit !== undefined && record.twelveMonthProfit >= 0
                          ? 'success'
                          : 'danger'
                      }
                    >
                      {formatMoney(record.twelveMonthProfit)}
                    </Text>
                  </td>
                  <td style={{ ...tdCss, maxWidth: 300, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                    {record.recommendation ?? '-'}
                  </td>
                  <td style={tdCenter}>
                    <Space size="small">
                      <button className={styles.linkBtn} onClick={() => handleEdit(record)}>
                        <i className="fas fa-edit" />
                      </button>
                      {record.status !== 'Completed' && (
                        <button className={styles.linkBtn} onClick={() => handleRun(record.id)}>
                          <i className="fas fa-play-circle" />
                        </button>
                      )}
                      <Popconfirm title="Xóa mô phỏng?" onConfirm={() => handleDelete(record.id)}>
                        <button className={styles.linkBtn} style={{ color: '#cf1322' }}>
                          <i className="fas fa-trash" />
                        </button>
                      </Popconfirm>
                    </Space>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      )}

      <Modal
        title={editing ? 'Cập nhật mô phỏng' : 'Mô phỏng mới'}
        open={modalOpen}
        onOk={handleSubmit}
        onCancel={() => setModalOpen(false)}
        okText={editing ? 'Cập nhật' : 'Tạo mới'}
        width={700}
        confirmLoading={submitting}
      >
        {/* ── Tên mô phỏng ── */}
        <div style={{ marginBottom: 16 }}>
          <label style={labelCss}>Tên mô phỏng</label>
          <input
            type="text"
            style={inputCss}
            placeholder="VD: Mở CH Foodmart Quận 9"
            value={formState.name}
            onChange={(e) => updateField('name', e.target.value)}
          />
        </div>

        <hr style={{ margin: '16px 0', border: 'none', borderTop: '1px solid #e8e8e8' }} />
        <Text strong style={{ display: 'block', marginBottom: 12, fontSize: 14 }}>
          Đầu tư ban đầu
        </Text>

        <div style={formRow}>
          <div style={col50}>
            <label style={labelCss}>Chi phí sửa chữa (VND)</label>
            {numInput('capexFitOut', '0')}
          </div>
          <div style={col50}>
            <label style={labelCss}>Trang thiết bị (VND)</label>
            {numInput('capexEquipment', '0')}
          </div>
        </div>

        <div style={formRow}>
          <div style={col50}>
            <label style={labelCss}>Chi phí trước khai trương</label>
            {numInput('preOpeningCost', '0')}
          </div>
          <div style={col50}>
            <label style={labelCss}>Vốn lưu động cần</label>
            {numInput('workingCapitalRequired', '0')}
          </div>
        </div>

        <div style={formRow}>
          <div style={col50}>
            <label style={labelCss}>Giá trị tồn kho ban đầu</label>
            {numInput('initialInventoryValue', '0')}
          </div>
          <div style={col50} />
        </div>

        <hr style={{ margin: '16px 0', border: 'none', borderTop: '1px solid #e8e8e8' }} />
        <Text strong style={{ display: 'block', marginBottom: 12, fontSize: 14 }}>
          Kinh doanh dự kiến
        </Text>

        <div style={formRow}>
          <div style={col50}>
            <label style={labelCss}>Doanh thu tháng ổn định (VND)</label>
            {numInput('projectedMonthlyRevenue', '0')}
          </div>
          <div style={col50}>
            <label style={labelCss}>Tỷ suất lãi gộp mục tiêu</label>
            <input
              type="number"
              style={inputCss}
              placeholder="0"
              min={0}
              max={100}
              value={formState.targetGrossMarginPercent ?? ''}
              onChange={(e) => updateField('targetGrossMarginPercent', e.target.value === '' ? '' : Number(e.target.value))}
            />
          </div>
        </div>

        <div style={formRow}>
          <div style={col50}>
            <label style={labelCss}>Chi phí cố định/tháng</label>
            {numInput('monthlyFixedCosts', '0')}
          </div>
          <div style={col50}>
            <label style={labelCss}>Số tháng ramp-up</label>
            <input
              type="number"
              style={inputCss}
              placeholder="3"
              min={1}
              max={12}
              value={formState.rampUpMonths ?? ''}
              onChange={(e) => updateField('rampUpMonths', e.target.value === '' ? '' : Number(e.target.value))}
            />
          </div>
        </div>

        <div style={formRow}>
          <div style={col50}>
            <label style={labelCss}>Phần trăm doanh thu trong giai đoạn ramp-up</label>
            <input
              type="number"
              style={inputCss}
              placeholder="50"
              min={1}
              max={100}
              value={formState.rampUpRevenuePercent ?? ''}
              onChange={(e) => updateField('rampUpRevenuePercent', e.target.value === '' ? '' : Number(e.target.value))}
            />
          </div>
          <div style={col50} />
        </div>
      </Modal>
    </div>
  );
}
